    <style>
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        :root {
            --navy-900: #0D1B3E; --navy-800: #122050; --navy-700: #1A2D6B;
            --accent-700: #B8870E; --accent-500: #F6BB33; --accent-300: #FAD97A; --accent-100: #FEF5DA;
            --paper: #EEF1F8; --paper-2: #EEF1F8; --white: #FFFFFF;
            --border-default: rgba(13,27,62,0.12); --border-subtle: rgba(13,27,62,0.07); --border-strong: rgba(13,27,62,0.22);
            --fg-secondary: #434966; --fg-tertiary: #8A8FA8;
            --success-100: #D4F0E3; --success-500: #1AA05F; --success-700: #147A47;
            --danger-500: #E53E3E;
            --shadow-xs: 0 1px 3px rgba(13,27,62,.06); --shadow-sm: 0 2px 8px rgba(13,27,62,.08);
            --shadow-md: 0 4px 16px rgba(13,27,62,.12); --shadow-lg: 0 8px 32px rgba(13,27,62,.16);
        }
        html { scroll-behavior: smooth; }
        body { font-family: 'Montserrat', sans-serif; color: var(--fg-secondary); background: #EEF1F8; -webkit-font-smoothing: antialiased; }
        h1, h2, h3, h4 { font-family: 'Montserrat', sans-serif; font-weight: 600 !important; }

        .container { max-width: 1160px; margin: 0 auto; padding: 0 24px; }
        .section { padding: 88px 0; }
        .section-band { background: var(--paper); }
        .section-inverse { background: var(--navy-900); }
        .eyebrow { font-size: 12px; font-weight: 600; letter-spacing: .12em; text-transform: uppercase; color: var(--fg-tertiary); }

        .btn { display: inline-flex; align-items: center; gap: 8px; padding: 12px 20px; border-radius: 10px; font-family: 'Montserrat', sans-serif; font-weight: 600; font-size: 15px; cursor: pointer; text-decoration: none; border: none; transition: all 200ms cubic-bezier(.16,1,.3,1); }
        .btn-lg { padding: 14px 24px; font-size: 16px; }
        .btn-primary { background: var(--navy-900); color: var(--paper); }
        .btn-primary:hover { background: var(--navy-700); }
        .btn-secondary { background: var(--paper-2); color: var(--navy-900); border: 1px solid var(--border-default); }
        .btn-secondary:hover { border-color: var(--navy-700); }
        .btn-ghost { background: transparent; color: var(--fg-secondary); }
        .btn-ghost:hover { color: var(--navy-900); }
        .btn-on-dark { background: var(--paper); color: var(--navy-900); }
        .btn-on-dark:hover { background: var(--accent-500); }

        /* Typing animation */
        @keyframes dotPulse { 0%,100%{opacity:.3;transform:scale(1)} 50%{opacity:1;transform:scale(1.2)} }
        .dot { width:6px; height:6px; border-radius:50%; background:#8A8FA8; display:inline-block; animation:dotPulse 1.4s infinite; }
        .dot:nth-child(2){animation-delay:.2s} .dot:nth-child(3){animation-delay:.4s}

        /* Scroll animations — CSS-driven, no JS required */
        @keyframes fadeUp { from{opacity:0;transform:translateY(20px)} to{opacity:1;transform:none} }
        .anim { animation: fadeUp .6s cubic-bezier(.16,1,.3,1) both; }
        .anim-d1 { animation-delay:.1s } .anim-d2 { animation-delay:.2s } .anim-d3 { animation-delay:.3s }

        /* Category cards */
        .cat-card { text-align:left; cursor:pointer; background:var(--white); border:1px solid var(--border-default); border-radius:14px; padding:28px; box-shadow:var(--shadow-xs); transition:all 200ms cubic-bezier(.16,1,.3,1); display:flex; flex-direction:column; font-family:inherit; width:100%; }
        .cat-card:hover { border-color:var(--navy-700); box-shadow:var(--shadow-md); }
        .cat-card.wide { flex-direction:row; align-items:center; gap:32px; padding:28px 32px; }
        .cat-card .arrow { transition:transform 200ms; }
        .cat-card:hover .arrow { transform:translateX(4px); }

        /* Channel tabs */
        .ch-tab { background:transparent; color:var(--navy-900); border:none; border-radius:10px; padding:14px 16px; cursor:pointer; font-family:inherit; font-weight:600; font-size:14px; display:flex; align-items:center; justify-content:center; gap:10px; transition:all 200ms cubic-bezier(.16,1,.3,1); }
        .ch-tab.active { background:var(--navy-900); color:var(--paper); }

        /* Channel panels */
        .ch-panel { display:none; }
        .ch-panel.active { display:block; }

        /* Decision tree */
        .dt-btn { display:flex; align-items:center; justify-content:space-between; gap:16px; padding:14px 16px; background:rgba(251,250,247,.06); border:1px solid rgba(251,250,247,.12); border-radius:10px; cursor:pointer; text-align:left; color:var(--paper); font-family:inherit; font-size:14px; transition:all 200ms cubic-bezier(.16,1,.3,1); width:100%; }
        .dt-btn.active { background:rgba(246,187,51,.14); border-color:var(--accent-500); }
        .dt-btn .dt-dest { font-size:12px; font-weight:600; color:rgba(251,250,247,.6); display:inline-flex; align-items:center; gap:6px; white-space:nowrap; }
        .dt-btn.active .dt-dest { color:var(--accent-500); }

        /* Form */
        .f-input { width:100%; padding:12px 14px; border:1px solid var(--border-strong); border-radius:10px; background:var(--white); font-size:15px; color:var(--navy-900); font-family:inherit; outline:none; transition:border-color 200ms,box-shadow 200ms; }
        .f-input:focus { border-color:var(--navy-700); box-shadow:0 0 0 3px rgba(26,45,107,.08); }
        .f-radio { display:flex; align-items:center; gap:10px; padding:12px 14px; border:1px solid var(--border-default); border-radius:10px; background:var(--white); cursor:pointer; font-size:14px; font-weight:500; color:var(--navy-900); transition:all 200ms cubic-bezier(.16,1,.3,1); }
        .f-radio.checked { border-color:var(--navy-700); background:var(--paper-2); }
        .f-radio-canal { justify-content:center; }
        .f-radio-canal.checked { background:var(--navy-900); color:var(--paper); border-color:var(--navy-900); }

        /* FAQ */
        .faq-item { border-bottom:1px solid var(--border-default); }
        .faq-item.hidden { display:none; }
        .faq-btn { width:100%; text-align:left; padding:24px 0; display:flex; align-items:flex-start; justify-content:space-between; gap:24px; background:transparent; border:none; cursor:pointer; font-family:'Montserrat',sans-serif; font-size:18px; line-height:26px; font-weight:700; color:var(--navy-900); }
        .faq-answer { display:none; padding-bottom:28px; padding-left:78px; font-size:16px; line-height:26px; color:var(--fg-secondary); }
        .faq-item.open .faq-answer { display:block; }
        .faq-tag { font-size:11px; font-weight:600; letter-spacing:.08em; text-transform:uppercase; background:var(--paper-2); color:var(--navy-900); padding:4px 10px; border-radius:999px; flex:none; margin-top:4px; transition:background 200ms; }
        .faq-item.open .faq-tag { background:var(--accent-500); }

        /* Filter buttons */
        .filter-btn { padding:6px 14px; font-size:13px; font-weight:500; border:1px solid var(--border-default); background:var(--white); color:var(--navy-900); border-radius:999px; cursor:pointer; font-family:inherit; transition:all 200ms; }
        .filter-btn.active { background:var(--navy-900); color:var(--paper); border-color:var(--navy-900); }

        /* Horarios table */
        .hor-row { display:grid; grid-template-columns:1.4fr 1.2fr 1.4fr; padding:20px 24px; border-top:1px solid var(--border-default); align-items:center; }
    </style>
</head>
