            <!-- Preset notice -->
            <div id="preset-notice" style="display:none; align-items:center; gap:10px; padding:10px 14px; background:var(--accent-100); border:1px solid var(--accent-300); border-radius:10px; margin-bottom:24px; font-size:13px; color:var(--navy-900);">
                <i data-lucide="check-circle-2" style="width:16px;height:16px;color:var(--accent-700);flex:none;"></i>
