            <!-- Form -->
            <form id="contact-form" onsubmit="submitForm(event)" style="background:var(--white); border:1px solid var(--border-default); border-radius:14px; padding:40px; box-shadow:var(--shadow-sm);">

                <div style="margin-bottom:20px;">
                    <label style="display:block; font-size:13px; font-weight:600; color:var(--navy-900); margin-bottom:8px;">Nombre completo <span style="color:var(--danger-500);">*</span></label>
                    <input id="f-nombre" type="text" class="f-input" placeholder="Tu nombre" required>
                </div>

                <div style="display:grid; grid-template-columns:1fr 1fr; gap:20px; margin-bottom:20px;">
                    <div>
                        <label style="display:block; font-size:13px; font-weight:600; color:var(--navy-900); margin-bottom:8px;">País de residencia <span style="color:var(--danger-500);">*</span></label>
                        <select id="f-pais" class="f-input" required>
                            <option value="">Selecciona…</option>
                            <option>Colombia</option><option>México</option><option>Argentina</option>
                            <option>Perú</option><option>Chile</option><option>Venezuela</option>
                            <option>Ecuador</option><option>Otro</option>
                        </select>
                    </div>
                    <div>
                        <label style="display:block; font-size:13px; font-weight:600; color:var(--navy-900); margin-bottom:8px;">Correo electrónico <span style="color:var(--danger-500);">*</span></label>
                        <input id="f-email" type="email" class="f-input" placeholder="tucorreo@@ejemplo.com" required>
                    </div>
                </div>

                <div style="margin-bottom:20px;">
                    <label style="display:flex; align-items:baseline; justify-content:space-between; margin-bottom:8px;">
                        <span style="font-size:13px; font-weight:600; color:var(--navy-900);">WhatsApp</span>
                        <span style="font-size:12px; color:var(--fg-tertiary);">opcional</span>
                    </label>
                    <input id="f-whatsapp" type="tel" class="f-input" placeholder="+57 300 000 0000">
                </div>

                <div style="margin-bottom:20px;">
                    <label style="display:block; font-size:13px; font-weight:600; color:var(--navy-900); margin-bottom:8px;">¿Sobre qué servicio consultas? <span style="color:var(--danger-500);">*</span></label>
                    <div style="display:grid; grid-template-columns:1fr 1fr; gap:8px;">
                        <label class="f-radio" id="srv-llc" onclick="selectService(this,'llc')"><input type="radio" name="servicio" value="llc" style="accent-color:var(--navy-700);" required><span>Crear LLC en EE.UU.</span></label>
