                        <label class="f-radio" id="srv-amazon" onclick="selectService(this,'amazon')"><input type="radio" name="servicio" value="amazon" style="accent-color:var(--navy-700);"><span>Vender en Amazon / Faire</span></label>
                        <label class="f-radio" id="srv-fda" onclick="selectService(this,'fda')"><input type="radio" name="servicio" value="fda" style="accent-color:var(--navy-700);"><span>Registro FDA</span></label>
                        <label class="f-radio" id="srv-trademark" onclick="selectService(this,'trademark')"><input type="radio" name="servicio" value="trademark" style="accent-color:var(--navy-700);"><span>Trademark</span></label>
                        <label class="f-radio" id="srv-general" onclick="selectService(this,'general')"><input type="radio" name="servicio" value="general" style="accent-color:var(--navy-700);"><span>Consulta general</span></label>
                    </div>
                </div>

                <div style="margin-bottom:20px;">
                    <label style="display:block; font-size:13px; font-weight:600; color:var(--navy-900); margin-bottom:8px;">Cuéntanos tu caso <span style="color:var(--danger-500);">*</span></label>
                    <textarea id="f-caso" class="f-input" rows="5" maxlength="500" placeholder="Describe brevemente tu situación: qué tienes actualmente, qué quieres lograr y cuál es tu principal duda." required style="font-family:inherit; resize:vertical;" oninput="updateCount(this)"></textarea>
                    <div style="font-size:12px; text-align:right; margin-top:6px; color:var(--fg-tertiary);" id="char-count">500 caracteres restantes</div>
                </div>

                <div style="margin-bottom:20px;">
                    <label style="display:block; font-size:13px; font-weight:600; color:var(--navy-900); margin-bottom:8px;">¿Cómo prefieres que te contactemos? <span style="color:var(--danger-500);">*</span></label>
                    <div style="display:grid; grid-template-columns:repeat(3,1fr); gap:8px;">
                        <label class="f-radio f-radio-canal checked" id="canal-email" onclick="selectCanal(this,'email')"><input type="radio" name="canal" value="email" checked style="display:none;"><i data-lucide="mail" style="width:16px;height:16px;"></i><span>Por email</span></label>
                        <label class="f-radio f-radio-canal" id="canal-wa" onclick="selectCanal(this,'whatsapp')"><input type="radio" name="canal" value="whatsapp" style="display:none;"><i data-lucide="message-circle" style="width:16px;height:16px;"></i><span>Por WhatsApp</span></label>
                        <label class="f-radio f-radio-canal" id="canal-call" onclick="selectCanal(this,'call')"><input type="radio" name="canal" value="call" style="display:none;"><i data-lucide="calendar-clock" style="width:16px;height:16px;"></i><span>Agendar llamada</span></label>
                    </div>
                </div>

                <div style="margin-top:32px; padding-top:24px; border-top:1px solid var(--border-default);">
                    <button type="submit" class="btn btn-primary btn-lg" style="width:100%; justify-content:center;"><span>Enviar mi consulta</span><i data-lucide="arrow-right" style="width:18px;height:18px;"></i></button>
                    <p style="font-size:13px; color:var(--fg-tertiary); text-align:center; margin-top:12px;">Te respondemos en menos de 24 h hábiles. No compartimos tus datos.</p>
                </div>
            </form>

            <!-- Confirmation -->
