</section>

<x-footer />

<script>
lucide.createIcons();

// ── Channel tabs ──────────────────────────────────────────────
var panels = ['ch-wa','ch-email','ch-form','ch-call'];
function setChannel(i) {
    document.querySelectorAll('.ch-tab').forEach(function(t,idx){ t.classList.toggle('active', idx===i); });
    document.querySelectorAll('.dt-btn').forEach(function(t,idx){ t.classList.toggle('active', idx===i); });
    panels.forEach(function(id,idx){
        var el = document.getElementById(id);
        if(el) el.classList.toggle('active', idx===i);
    });
}

// ── Category → form ───────────────────────────────────────────
function pickCategory(svc) {
    var radio = document.querySelector('input[name="servicio"][value="'+svc+'"]');
    if(radio){ radio.checked = true; selectService(radio.closest('label'), svc); }
    document.getElementById('preset-notice').style.display = 'flex';
    var el = document.getElementById('formulario');
    if(el){ var top = el.getBoundingClientRect().top + window.scrollY - 80; window.scrollTo({top:top, behavior:'smooth'}); }
}

// ── Form helpers ──────────────────────────────────────────────
function selectService(el, svc) {
    document.querySelectorAll('.f-radio[id^="srv-"]').forEach(function(l){ l.classList.remove('checked'); });
    if(el) el.classList.add('checked');
}
function selectCanal(el, val) {
    document.querySelectorAll('.f-radio-canal').forEach(function(l){ l.classList.remove('checked'); });
    el.classList.add('checked');
    el.querySelector('input').checked = true;
}
function updateCount(ta) {
    var left = 500 - ta.value.length;
    var el = document.getElementById('char-count');
    if(el){ el.textContent = left + ' caracteres restantes'; el.style.color = left < 50 ? 'var(--accent-700)' : 'var(--fg-tertiary)'; }
}

// ── Form submit ───────────────────────────────────────────────
function submitForm(e) {
    e.preventDefault();
    var nombre   = document.getElementById('f-nombre').value.trim();
    var pais     = document.getElementById('f-pais').value;
    var email    = document.getElementById('f-email').value.trim();
    var whatsapp = document.getElementById('f-whatsapp').value.trim();
    var caso     = document.getElementById('f-caso').value.trim();
    var svcEl    = document.querySelector('input[name="servicio"]:checked');
    var canalEl  = document.querySelector('input[name="canal"]:checked');
    var svc = svcEl ? svcEl.value : 'general';
    var canal = canalEl ? canalEl.value : 'email';
    var svcLabels = {llc:'LLC',itin:'ITIN',amazon:'Amazon/Faire',fda:'FDA',trademark:'Trademark',general:'Consulta general'};
    var canalLabels = {email:'tu correo',whatsapp:'WhatsApp','call':'una llamada agendada'};
    var ticket = 'SU-' + String(Date.now()).slice(-6);

    document.getElementById('confirm-title').textContent = nombre ? 'Recibimos tu mensaje, ' + nombre.split(' ')[0] + '.' : 'Recibimos tu mensaje.';
    document.getElementById('confirm-body').innerHTML = 'Un especialista revisará tu caso y te contactará por <strong style="color:var(--navy-900);">' + (canalLabels[canal]||canal) + '</strong> en menos de <strong style="color:var(--navy-900);">24 h hábiles</strong>.';
    document.getElementById('confirm-summary').innerHTML = '<div style="display:grid;grid-template-columns:110px 1fr;gap:14px;font-size:14px;"><span style="color:var(--fg-tertiary);">Categoría</span><span style="font-weight:600;color:var(--navy-900);">'+(svcLabels[svc]||svc)+'</span><span style="color:var(--fg-tertiary);">Email</span><span style="font-weight:600;color:var(--navy-900);">'+email+'</span>'+(whatsapp?'<span style="color:var(--fg-tertiary);">WhatsApp</span><span style="font-weight:600;color:var(--navy-900);">'+whatsapp+'</span>':'')+'<span style="color:var(--fg-tertiary);">Ticket</span><span style="font-weight:700;color:var(--navy-900);">'+ticket+'</span></div>';

    document.getElementById('contact-form').style.display = 'none';
    document.getElementById('form-confirm').style.display = 'block';
    lucide.createIcons();

    var msg = encodeURIComponent('Hola, soy ' + nombre + ' de ' + pais + '. Consulta sobre: ' + (svcLabels[svc]||svc) + '. ' + caso + ' (Email: ' + email + ')');
    setTimeout(function(){ window.open('https://wa.me/573116473200?text='+msg,'_blank'); }, 500);
}
function resetForm() {
    document.getElementById('contact-form').reset();
    document.getElementById('contact-form').style.display = 'block';
    document.getElementById('form-confirm').style.display = 'none';
    document.getElementById('preset-notice').style.display = 'none';
    document.querySelectorAll('.f-radio').forEach(function(l){ l.classList.remove('checked'); });
    document.getElementById('canal-email').classList.add('checked');
    document.getElementById('char-count').textContent = '500 caracteres restantes';
}

// ── FAQ ───────────────────────────────────────────────────────
function toggleFaq(btn) {
    var item = btn.closest('.faq-item');
    var wasOpen = item.classList.contains('open');
    document.querySelectorAll('.faq-item.open').forEach(function(el){ el.classList.remove('open'); el.querySelector('.faq-btn i').setAttribute('data-lucide','plus'); });
    if(!wasOpen){ item.classList.add('open'); btn.querySelector('i').setAttribute('data-lucide','minus'); }
    lucide.createIcons();
}
function filterFaq(btn, tag) {
    document.querySelectorAll('.filter-btn').forEach(function(b){ b.classList.remove('active'); });
    btn.classList.add('active');
    document.querySelectorAll('.faq-item').forEach(function(el){
        el.classList.toggle('hidden', tag !== 'Todas' && el.dataset.tag !== tag);
    });
    document.querySelectorAll('.faq-item.open').forEach(function(el){ el.classList.remove('open'); });
}
</script>
</body>
</html>
